"use client";

import { motion } from "framer-motion";
import {
  Users,
  BookOpen,
  GraduationCap,
  Library,
  Calendar,
  Bell,
  TrendingUp,
  Clock,
} from "lucide-react";
import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/lib/auth-context";

import { PageHeader } from "@/components/ui/page-header";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  dashboardStats,
  recentActivities,
  upcomingEvents,
} from "@/data/mockData";
import { LiveAnnouncements } from "@/components/LiveAnnouncements";


/* ---------------- Animations ---------------- */
const container = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.12 },
  },
};

const item = {
  hidden: { opacity: 0, y: 20 },
  show: { opacity: 1, y: 0 },
};

/* ---------------- Icons ---------------- */
const iconMap: Record<number, React.ReactNode> = {
  1: <Users className="h-6 w-6 text-primary" />,
  2: <BookOpen className="h-6 w-6 text-primary" />,
  3: <GraduationCap className="h-6 w-6 text-primary" />,
  4: <Library className="h-6 w-6 text-primary" />,
};

/* ---------------- Badge Colors ---------------- */
const eventTypeColors: Record<string, string> = {
  exam: "bg-red-100 text-red-600",
  event: "bg-primary/10 text-primary",
  sports: "bg-emerald-100 text-emerald-600",
};

/* ====================================================== */

export default function DashboardPage() {
  const { user, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (!loading && !user) {
      router.replace("/login");
    }
  }, [user, loading, router]);

  if (loading || !user) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-white">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent"></div>
      </div>
    );
  }

  return (
    <PageHeader
      title="Strategic Dashboard"
      description={`Salutations, ${user?.firstName}! Intelligence overview for the Vidyahub decentralized campus ecosystem is now live.`}
      actions={
        <div className="flex bg-white/10 p-1.5 rounded-2xl backdrop-blur-md border border-white/20 gap-3">
           <Button className="h-10 px-6 bg-primary text-primary hover:bg-white/90 hover:text-primary rounded-xl font-bold flex items-center gap-2">
            <Bell className="w-4 h-4" />
            V-Intelligence
          </Button>
        </div>
      }
    >
      <div className="space-y-8 md:space-y-12">
        {/* ================= STATS ================= */}
        <motion.div
          variants={container}
          initial="hidden"
          animate="show"
          className="grid gap-4 md:gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-4"
        >
          {dashboardStats.map((stat) => (
            <motion.div key={stat.id} variants={item}>
              <Card className="rounded-[1.5rem] md:rounded-[2rem] border-0 bg-white shadow-sm group hover:shadow-2xl transition-all duration-500 overflow-hidden relative">
                 <div className="absolute top-0 right-0 p-4 md:p-8 opacity-5 group-hover:scale-110 transition-transform duration-500">
                    {iconMap[stat.id] && <div className="scale-[1.2] md:scale-[2]">{iconMap[stat.id]}</div>}
                 </div>
                  <CardContent className="p-6 md:p-8 space-y-3 md:space-y-4">
                    <p className="text-[9px] md:text-[10px] font-black text-muted-foreground uppercase tracking-[0.2em]">{stat.title}</p>
                    <div className="space-y-1">
                       <h3 className="text-3xl md:text-4xl font-black italic tracking-tighter text-gray-900">{stat.value}</h3>
                       <div className="flex items-center gap-2">
                          <Badge className={`${stat.trend === 'up' ? 'bg-emerald-500' : 'bg-rose-500'} text-white border-0 rounded-lg text-[8px] md:text-[9px] font-black h-5`}>
                             {stat.change}
                          </Badge>
                          <span className="text-[8px] md:text-[9px] font-bold text-muted-foreground uppercase tracking-widest">Global Shift</span>
                       </div>
                    </div>
                  </CardContent>
              </Card>
            </motion.div>
          ))}
        </motion.div>

        {/* ================= MIDDLE GRID ================= */}
        <div className="grid gap-6 md:gap-8 lg:grid-cols-3">
          {/* -------- RECENT ACTIVITIES -------- */}
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            className="lg:col-span-2"
          >
            <Card className="rounded-[1.5rem] md:rounded-[2.5rem] border-2 shadow-sm bg-white overflow-hidden">
              <CardHeader className="p-6 md:p-10 pb-4 flex flex-row items-center justify-between">
                <div className="space-y-1">
                   <CardTitle className="text-xl md:text-2xl font-black italic tracking-tight uppercase flex items-center gap-3">
                     <Clock className="h-5 w-5 md:h-6 md:w-6 text-primary" />
                     Live Activity Stream
                   </CardTitle>
                </div>
                <Button variant="ghost" className="rounded-xl font-bold text-primary italic uppercase tracking-widest text-[10px] md:text-xs">
                  Full Audit Log
                </Button>
              </CardHeader>

              <CardContent className="p-6 md:p-10 pt-0">
                <LiveAnnouncements />
              </CardContent>
            </Card>
          </motion.div>

          {/* -------- UPCOMING EVENTS -------- */}
          <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
          >
            <Card className="rounded-[1.5rem] md:rounded-[2.5rem] border-0 shadow-sm bg-white overflow-hidden">
              <CardHeader className="p-6 md:p-10 pb-4 flex flex-row items-center justify-between">
                <CardTitle className="text-xl md:text-2xl font-black italic tracking-tight uppercase flex items-center gap-3">
                  <Calendar className="h-5 w-5 md:h-6 md:w-6 text-primary" />
                  Upcoming
                </CardTitle>
                <Button variant="ghost" className="rounded-xl font-bold text-primary italic uppercase tracking-widest text-[10px] md:text-xs">
                  Calendar
                </Button>
              </CardHeader>

              <CardContent className="p-6 md:p-10 pt-0">
                <div className="space-y-3 md:space-y-4">
                  {upcomingEvents.map((event, index) => (
                    <motion.div
                      key={event.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: index * 0.08 }}
                      className="flex flex-col gap-2 md:gap-3 rounded-[1rem] md:rounded-[1.5rem] bg-secondary/5 p-4 md:p-6 border border-transparent hover:border-primary/5 transition-all"
                    >
                       <div className="flex justify-between items-start">
                          <Badge className={`${eventTypeColors[event.type] || "bg-secondary text-secondary-foreground"} border-0 h-5 md:h-6 px-2 md:px-3 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-widest`}>
                            {event.type}
                          </Badge>
                          <p className="text-[8px] md:text-[10px] font-bold text-muted-foreground uppercase">{event.date}</p>
                       </div>
                       <p className="text-xs md:text-sm font-black text-gray-900 uppercase italic tracking-tight">{event.title}</p>
                    </motion.div>
                  ))}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        </div>

        {/* ================= CAMPUS HUB ================= */}
        <div className="space-y-8 md:space-y-12">
          <div className="flex items-center gap-4 md:gap-6 px-2 md:px-4">
             <h2 className="text-2xl md:text-4xl font-black italic tracking-tighter text-gray-900 uppercase">CAMPUS HUB OPERATIONS</h2>
             <div className="flex-1 h-[2px] bg-secondary/10" />
          </div>

          <div className="grid gap-6 md:gap-8 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
            {[
              {
                title: "Academic & Curriculum",
                icon: GraduationCap,
                color: "bg-primary",
                description: "Managing core pedagogical trajectories",
                links: [
                  { name: "Timetable", href: "/timetable" },
                  { name: "GPA Monitor", href: "/gpa-calculator" },
                  { name: "Syllabus Index", href: "/syllabus" },
                  { name: "Analytics", href: "/performance" },
                ]
              },
              {
                title: "Hostel & Logistics",
                icon: BookOpen,
                color: "bg-emerald-500",
                description: "Residential operations & sustenance",
                links: [
                  { name: "Mess Tracker", href: "/mess" },
                  { name: "Laundry Ops", href: "/laundry" },
                  { name: "Inventory", href: "/room" },
                  { name: "Night Feed", href: "/canteen" },
                ]
              },
              {
                title: "Career & Synergy",
                icon: TrendingUp,
                color: "bg-purple-500",
                description: "Professional alignment & networking",
                links: [
                  { name: "Alumni Unity", href: "/alumni" },
                  { name: "Live Panels", href: "/interviews" },
                  { name: "Resume Vault", href: "/resume" },
                  { name: "Guild Partners", href: "/partners" },
                ]
              },
              {
                title: "Support Engineering",
                icon: Library,
                color: "bg-orange-500",
                description: "Optimization & crisis management",
                links: [
                  { name: "Network Ops", href: "/wifi" },
                  { name: "Clinical Hub", href: "/counseling" },
                  { name: "Asset Recovery", href: "/lost-found" },
                  { name: "Grants Board", href: "/scholarships" },
                ]
              },
              {
                title: "Culture & Engagement",
                icon: Calendar,
                color: "bg-rose-500",
                description: "Social capital & festivity index",
                links: [
                  { name: "Fest Access", href: "/events" },
                  { name: "Equipment Pool", href: "/sports" },
                  { name: "Guild Registry", href: "/clubs" },
                  { name: "Talent Feed", href: "/talent" },
                ]
              }
            ].map((section, idx) => (
              <motion.div
                key={section.title}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.1 * idx }}
              >
                <Card className="h-full rounded-[2rem] md:rounded-[3rem] border-0 shadow-sm hover:shadow-2xl transition-all duration-500 group overflow-hidden bg-white">
                  <div className={`h-1.5 md:h-2 w-full ${section.color} opacity-40 group-hover:opacity-100 transition-opacity`} />
                  <CardHeader className="p-6 md:p-10 pb-6">
                    <div className="flex items-center gap-4 md:gap-6">
                      <div className={`w-12 h-12 md:w-14 md:h-14 rounded-xl md:rounded-2xl ${section.color}/10 flex items-center justify-center text-${section.color.split('-')[1]}-600 ring-1 ring-${section.color.split('-')[1]}-600/20`}>
                        <section.icon className="h-6 w-6 md:h-7 md:w-7" />
                      </div>
                      <div className="space-y-0.5 md:space-y-1">
                        <CardTitle className="text-lg md:text-xl font-black uppercase tracking-tight italic">{section.title}</CardTitle>
                        <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground opacity-50">{section.description}</p>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent className="p-6 md:p-10 pt-0">
                    <div className="grid grid-cols-2 gap-3 md:gap-4">
                      {section.links.map((link) => (
                        <Button
                          key={link.name}
                          variant="ghost"
                          className="justify-start h-10 md:h-12 rounded-xl bg-secondary/5 hover:bg-primary/10 hover:text-primary border border-transparent hover:border-primary/10 transition-all font-bold text-[10px] md:text-xs uppercase tracking-widest px-3 md:px-4"
                          onClick={() => router.push(link.href)}
                        >
                          {link.name}
                        </Button>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </PageHeader>
  );
}

"use client";

import { useAnnouncements } from "@/hooks/useAnnouncements";
import { Megaphone, Bell, Loader2, Clock } from "lucide-react";
import { motion } from "framer-motion";
import { Badge } from "@/components/ui/badge";
import { formatDistanceToNow } from "date-fns";

export function LiveAnnouncements() {
  const { announcements, loading } = useAnnouncements(3);

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8 bg-secondary/5 rounded-3xl border border-secondary/10">
        <Loader2 className="h-5 w-5 animate-spin text-primary" />
      </div>
    );
  }

  if (announcements.length === 0) {
    return (
      <div className="p-8 text-center bg-secondary/5 rounded-3xl border border-secondary/10">
        <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">No active transmissions</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {announcements.map((item, index) => (
        <motion.div
          key={item.id}
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: index * 0.1 }}
          className="group relative flex flex-col gap-3 p-6 bg-white rounded-3xl border border-secondary/10 hover:shadow-xl hover:border-primary/20 transition-all duration-500 overflow-hidden"
        >
          {/* Subtle Glow */}
          <div className="absolute top-0 right-0 -mr-4 -mt-4 w-12 h-12 bg-primary/5 blur-2xl rounded-full group-hover:bg-primary/10 transition-colors" />
          
          <div className="flex justify-between items-start">
            <div className="flex items-center gap-3">
              <div className="h-8 w-8 rounded-xl bg-primary/10 flex items-center justify-center text-primary">
                <Megaphone className="h-4 w-4" />
              </div>
              <Badge className={`${item.tag === 'Global Sync' ? 'bg-primary/10 text-primary' : 'bg-rose-100 text-rose-600'} border-0 h-5 px-2 rounded-lg text-[8px] font-black uppercase tracking-widest`}>
                {item.tag}
              </Badge>
            </div>
            <div className="flex items-center gap-1.5 text-muted-foreground">
              <Clock className="h-3 w-3" />
              <span className="text-[9px] font-bold uppercase tracking-widest">
                {item.createdAt ? formatDistanceToNow(item.createdAt.toDate(), { addSuffix: true }) : "Recent"}
              </span>
            </div>
          </div>

          <div className="space-y-1">
            <h4 className="text-sm font-black italic tracking-tight text-gray-900 uppercase">{item.title}</h4>
            <p className="text-xs text-muted-foreground font-medium leading-relaxed line-clamp-2 group-hover:line-clamp-none transition-all duration-500">
              {item.message}
            </p>
          </div>
        </motion.div>
      ))}
    </div>
  );
}

const functions = require("firebase-functions");
const admin = require("firebase-admin");
const nodemailer = require("nodemailer");

admin.initializeApp();

// Configure the email transport using Gmail and App Password
// These are set via: firebase functions:secrets:set GMAIL_EMAIL GMAIL_PASSWORD
const transporter = nodemailer.createTransport({
  service: "gmail",
  auth: {
    user: process.env.GMAIL_EMAIL,
    pass: process.env.GMAIL_PASSWORD,
  },
});

/**
 * Triggered when a new result is added to the 'results' collection.
 */
exports.sendResultEmail = functions.firestore
  .document("results/{resultId}")
  .onCreate(async (snap, context) => {
    const resultData = snap.data();
    const studentId = resultData.studentId;

    if (!studentId) {
      console.log("No studentId found in the result document.");
      return null;
    }

    try {
      // 1. Fetch student details from the 'users' collection
      const userDoc = await admin.firestore().collection("users").doc(studentId).get();

      if (!userDoc.exists) {
        console.log(`User document not found for studentId: ${studentId}`);
        return null;
      }

      const userData = userDoc.data();
      const studentEmail = userData.email;
      const studentName = userData.name || userData.firstName || "Student";

      if (!studentEmail) {
        console.log(`No email found for student: ${studentName}`);
        return null;
      }

      // 2. Construct the email
      const mailOptions = {
        from: `"VidyaHub Portal" <${process.env.GMAIL_EMAIL}>`,
        to: studentEmail,
        subject: `Academic Performance Update - ${resultData.subject || "New Result"}`,
        html: `
          <div style="font-family: Arial, sans-serif; padding: 20px; color: #333;">
            <h2 style="color: #0b1220;">Hello ${studentName},</h2>
            <p>Your scholastic audit for <b>${resultData.subject || "your recent test"}</b> has been manifested.</p>
            <div style="background: #f8fafc; padding: 15px; border-radius: 10px; border: 1px solid #e2e8f0;">
              <p style="margin: 0;"><b>Subject:</b> ${resultData.subject || "N/A"}</p>
              <p style="margin: 5px 0;"><b>Score Matrix:</b> ${resultData.marks || "0"} / ${resultData.totalMarks || "100"}</p>
              <p style="margin: 0;"><b>Status:</b> Validated</p>
            </div>
            <p style="margin-top: 20px;">You can view the full report by logging into your <a href="https://vidyahub.edu/dashboard" style="color: #0b1220; font-weight: bold;">Intelligence Dashboard</a>.</p>
            <br>
            <p>Best Regards,<br><b>Registry Node - VidyaHub</b></p>
          </div>
        `,
      };

      // 3. Send the email
      await transporter.sendMail(mailOptions);
      console.log(`Email successfully dispatched to: ${studentEmail}`);
      return { success: true };

    } catch (error) {
      console.error("Transmission Error:", error);
      return null;
    }
  });

const { execSync } = require('child_process');
const fs = require('fs');

var output = [];
try {
  execSync('npx eslint app components lib --quiet --format=json', {
    stdio: ['ignore', 'pipe', 'pipe'],
    maxBuffer: 20 * 1024 * 1024
  });
  output.push('No errors found!');
} catch (e) {
  var results = JSON.parse(e.stdout.toString());
  results.forEach(function(r) {
    if (r.errorCount > 0) {
      r.messages.forEach(function(m) {
        if (m.severity === 2) {
          output.push(r.filePath + ':' + m.line + ':' + m.column + ' [' + m.ruleId + '] ' + m.message);
        }
      });
    }
  });
}

fs.writeFileSync('eslint_errors.json', JSON.stringify(output, null, 2), 'utf8');
console.log('Done. Found ' + output.length + ' errors. Written to eslint_errors.json');
output.forEach(function(line) { console.log(line); });

import { initializeApp, getApps, getApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import {
  getFirestore,
  initializeFirestore,
  persistentMultipleTabManager,
  persistentLocalCache,
} from "firebase/firestore";
import { getAnalytics, isSupported, type Analytics } from "firebase/analytics";

const firebaseConfig = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY as string,
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN as string,
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID as string,
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET as string,
  messagingSenderId: process.env
    .NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID as string,
  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID as string,
  measurementId: process.env.NEXT_PUBLIC_FIREBASE_MEASUREMENT_ID as string,
};

// Initialize Firebase (Singleton pattern for Next.js)
const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApp();
const auth = getAuth(app);

// Initialize Firestore with modern persistent cache
let db: ReturnType<typeof getFirestore>;

if (typeof window !== "undefined") {
  // Browser: use persistent multi-tab cache
  const existingDb = (app as unknown as { _db: typeof db })._db;
  if (existingDb) {
    db = existingDb;
  } else {
    try {
      db = initializeFirestore(app, {
        localCache: persistentLocalCache({
          tabManager: persistentMultipleTabManager(),
        }),
      }, process.env.NEXT_PUBLIC_FIREBASE_DATABASE_ID || "(default)");
      (app as unknown as { _db: typeof db })._db = db;
    } catch (e) {
      db = getFirestore(app, process.env.NEXT_PUBLIC_FIREBASE_DATABASE_ID || "(default)");
    }
  }
} else {
  // Server-side rendering: no persistence
  db = getFirestore(app, process.env.NEXT_PUBLIC_FIREBASE_DATABASE_ID || "(default)");
}

// Initialize Analytics conditionally
let analytics: Analytics | undefined;
if (typeof window !== "undefined") {
  isSupported().then((supported) => {
    if (supported) analytics = getAnalytics(app);
  });
}

export { app, auth, db, analytics };

import { NextResponse, NextRequest } from 'next/server';

// We only use this for basic routing protection.
// Actual auth state is handled by AuthProvider (client-side).
export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // We are not using cookies for auth yet, so we rely on the client-side AuthProvider
  // to handle redirects. However, we can ensure that /dashboard exists and is handled.
  
  // If we wanted to use middleware for protection, we would check for a session cookie here.
  // For now, we'll just let Next.js continue.
  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/login', '/signup'],
};

